mapper.select:
SELECT DISTINCT p.* FROM sys_permission p INNER JOIN sys_role_permission rp ON p.id = rp.permission_id INNER JOIN sys_role r ON rp.role_id = r.id INNER JOIN sys_user_role ur ON r.id = ur.role_id WHERE ur.user_id = #{userId} AND p.permission_type = 'menu' AND p.visible = 1 AND p.status = 1 AND p.deleted = 0 AND rp.deleted = 0 AND r.deleted = 0 AND ur.deleted = 0
AND p.system_code = #{systemCode}
ORDER BY p.sort_order ASC
